   1 | <!DOCTYPE html>
   2 | <html lang="zh-Hant">
   3 | <head>
   4 |     <meta charset="UTF-8">
   5 |     <meta name="viewport" content="width=device-width, initial-scale=1.0">
   6 |     <title>VCC PRE 廣播主控室操作員矩陣首頁系統 v0.5</title>
   7 |     <style>
   8 |         body {
   9 |             margin: 0;
  10 |             padding: 0;
  11 |             background-color: #090d16;
  12 |             font-family: "Microsoft JhengHei", "微軟正黑體", Arial, sans-serif;
  13 |         }
  14 | 
  15 |         /* 獨立沙盒包裝層 */
  16 |         .vcc-pre-system-sandbox-wrapper {
  17 |             --sidebar-width: 260px;
  18 |             --primary-color: #38bdf8;
  19 |             --bg-dark: #090d16;
  20 |             --bg-panel: #111827;
  21 |             --success: #10b981;
  22 |             --warning: #f59e0b;
  23 |             --danger: #ef4444;
  24 |             --on-air: #22c55e;
  25 | 
  26 |             display: flex !important;
  27 |             width: 100% !important;
  28 |             height: 100vh !important;
  29 |             min-height: 780px;
  30 |             background-color: var(--bg-dark);
  31 |             color: #f1f5f9;
  32 |             box-sizing: border-box;
  33 |             overflow: hidden !important;
  34 |             position: relative;
  35 |         }
  36 | 
  37 |         .vcc-pre-system-sandbox-wrapper *,
  38 |         .vcc-pre-system-sandbox-wrapper *:before,
  39 |         .vcc-pre-system-sandbox-wrapper *:after {
  40 |             box-sizing: border-box;
  41 |         }
  42 | 
  43 |         /* 左側常駐工作列 */
  44 |         .sidebar {
  45 |             width: var(--sidebar-width);
  46 |             min-width: var(--sidebar-width);
  47 |             background-color: var(--bg-panel);
  48 |             border-right: 1px solid #1f2937;
  49 |             display: flex;
  50 |             flex-direction: column;
  51 |             justify-content: space-between;
  52 |             height: 100%;
  53 |             z-index: 10;
  54 |         }
  55 |         .sidebar-header {
  56 |             padding: 24px 20px;
  57 |             text-align: center;
  58 |             font-size: 16px;
  59 |             font-weight: bold;
  60 |             letter-spacing: 1px;
  61 |             color: var(--primary-color);
  62 |             border-bottom: 1px solid #1f2937;
  63 |             background: linear-gradient(180deg, rgba(56,189,248,0.05) 0%, rgba(0,0,0,0) 100%);
  64 |         }
  65 |         .sidebar-menu { flex: 1; padding: 20px 0; }
  66 |         .menu-item {
  67 |             padding: 15px 20px; color: #9ca3af; cursor: pointer; font-size: 14px; display: flex; align-items: center; gap: 12px; transition: all 0.2s;
  68 |         }
  69 |         .menu-item:hover { background-color: rgba(56, 189, 248, 0.04); color: #fff; }
  70 |         .menu-item.active {
  71 |             background-color: rgba(56, 189, 248, 0.08); color: var(--primary-color); border-left: 4px solid var(--primary-color); font-weight: bold;
  72 |         }
  73 |         .sidebar-footer { padding: 20px; font-size: 11px; color: #4b5563; text-align: center; border-top: 1px solid #1f2937; line-height: 1.6; }
  74 | 
  75 |         /* 右側核心工作區 */
  76 |         .main-content { flex: 1; padding: 25px; overflow-y: auto !important; height: 100%; background-color: var(--bg-dark); }
  77 |         .page { display: none; }
  78 |         .page.active { display: block; }
  79 | 
  80 |         /* 模組容器 */
  81 |         .panel-box {
  82 |             background-color: var(--bg-panel); padding: 22px; border-radius: 8px; box-shadow: 0 10px 25px -5px rgba(0, 0, 0, 0.7); margin-bottom: 20px; border: 1px solid #1f2937;
  83 |         }
  84 |         .panel-header-box {
  85 |             display: flex; justify-content: space-between; align-items: center; margin-bottom: 18px; border-bottom: 1px solid #1f2937; padding-bottom: 10px;
  86 |         }
  87 |         .panel-title { font-size: 14px; color: var(--primary-color); font-weight: bold; letter-spacing: 0.5px; text-transform: uppercase; }
  88 | 
  89 |         /* 廣播主控專用：頂部極致三欄網格佈局 (首頁專用) */
  90 |         .mcr-operator-grid {
  91 |             display: grid;
  92 |             grid-template-columns: 1.2fr 1fr;
  93 |             gap: 20px;
  94 |             margin-bottom: 20px;
  95 |         }
  96 |         @media(max-width: 1200px) { .mcr-operator-grid { grid-template-columns: 1fr; } }
  97 | 
  98 |         /* MCR On-Air 監測監視器樣式 */
  99 |         .mcr-monitor-card {
 100 |             background: linear-gradient(135deg, #0b1519 0%, #111827 100%);
 101 |             border: 2px solid #10b981;
 102 |             border-radius: 8px;
 103 |             padding: 20px;
 104 |             position: relative;
 105 |             box-shadow: 0 0 20px rgba(16, 185, 129, 0.1);
 106 |         }
 107 |         .mcr-monitor-card.no-active {
 108 |             border-color: #374151;
 109 |             box-shadow: none;
 110 |         }
 111 |         .mcr-tag-live {
 112 |             position: absolute; top: 15px; right: 20px; background-color: var(--on-air); color: #fff; padding: 3px 8px; font-size: 11px; font-weight: bold; border-radius: 4px; letter-spacing: 1px; animation: blinker 1.5s linear infinite;
 113 |         }
 114 |         @keyframes blinker { 50% { opacity: 0.3; } }
 115 | 
 116 |         .mcr-label-sub { font-size: 12px; color: #9ca3af; text-transform: uppercase; margin-bottom: 4px; font-weight: 600; }
 117 |         .mcr-prog-title { font-size: 26px; font-weight: 900; color: #ffffff; margin: 5px 0 15px 0; letter-spacing: 0.5px; text-shadow: 0 2px 4px rgba(0,0,0,0.5); }
 118 |         .mcr-prog-countdown { font-family: 'Courier New', Courier, monospace; font-size: 24px; color: var(--warning); font-weight: bold; }
 119 |         .mcr-next-bar { background-color: rgba(255,255,255,0.03); border-left: 3px solid var(--primary-color); padding: 10px 15px; margin-top: 15px; border-radius: 0 4px 4px 0; }
