 131 |         /* 雙欄排版（用於行事曆與表單對齊） */
 132 |         .grid-layout-2col { display: grid; grid-template-columns: 340px 1fr; gap: 20px; margin-bottom: 20px; }
 133 |         @media(max-width: 1024px) { .grid-layout-2col { grid-template-columns: 1fr; } }
