 135 |         /* --- NATIVE GUI CALENDAR STYLE --- */
 136 |         .gui-calendar-card { background: #090d16; border: 1px solid #1f2937; border-radius: 6px; padding: 12px; }
 137 |         .calendar-nav-header { display: flex; justify-content: space-between; align-items: center; margin-bottom: 10px; }
 138 |         .calendar-nav-header span { font-size: 14px; font-weight: bold; color: #fff; }
 139 |         .calendar-nav-btn { background: #1f2937; color: #fff; padding: 4px 8px; font-size: 12px; border-radius: 4px; cursor: pointer; }
