 142 |         .calendar-grid-body { display: grid; grid-template-columns: repeat(7, 1fr); gap: 4px; text-align: center; }
 143 |         .calendar-day-cell {
 144 |             aspect-ratio: 1; background: #111827; border-radius: 6px; display: flex; flex-direction: column; justify-content: center; align-items: center; font-size: 13px; font-family: monospace; cursor: pointer; position: relative; transition: all 0.15s; border: 1px solid transparent; color: #cbd5e1; gap:1px;
 145 |         }
