 149 |         .calendar-day-cell.today { border: 1px solid var(--success); }
 150 |         .calendar-day-cell.selected.today { border-color: var(--primary-color) !important; }
 151 |         .calendar-prog-count { font-size:9px; color:#64748b; font-weight:normal; font-family:sans-serif; }
 152 |         .calendar-day-cell.selected .calendar-prog-count { color:#090d16; opacity:0.7; }
 153 |         .calendar-day-cell.has-progs { border-bottom:2px solid #a855f7; }
