 159 |         .input-group label { font-size: 12px; color: #9ca3af; margin-bottom: 4px; }
 160 |         .input-group input, .input-group select, .input-group textarea {
 161 |             background-color: #090d16; border: 1px solid #374151; color: #fff; padding: 8px 10px; border-radius: 4px; font-size: 13px; outline: none;
 162 |         }
 163 |         .input-group input:focus, .input-group select:focus, .input-group textarea:focus { border-color: var(--primary-color); }
 164 |         /* 窄螢幕響應式: 768px 以下調整表單成單欄 */
 165 |         @media (max-width: 768px) {
 166 |             .input-form { grid-template-columns: 1fr; }
