 171 |         /* 頂部全局控制列 */
 172 |         .global-filter-bar {
 173 |             background: #111827; padding: 12px 20px; border-radius: 6px; margin-bottom: 20px; display: flex; align-items: center; gap: 15px; border: 1px solid #1f2937;
 174 |         }
 175 |         .global-filter-bar input[type="date"] { background: #090d16; border: 1px solid #374151; color: #fff; padding: 6px 10px; border-radius: 4px; }
 176 | 
