 178 |         .btn-zone { display: flex; gap: 10px; margin-top: 10px; }
 179 |         button { padding: 9px 14px; font-size: 12px; font-weight: bold; border-radius: 4px; cursor: pointer; border: none; transition: all 0.2s; }
 180 |         .btn-add { background-color: #0284c7; color: white; }
 181 |         .btn-update { background-color: var(--warning); color: #090d16; }
 182 |         .btn-start { background-color: var(--success); color: white; font-size: 13px; padding: 10px 20px; box-shadow: 0 0 10px rgba(16,185,129,0.2); }
 183 |         .btn-sync { background-color: #374151; color: white; }
 184 |         .btn-cancel { background-color: #4b5563; color: white; }
