 192 | 
 193 |         /* HUD 全域看板 */
 194 |         .status-panel {
 195 |             background-color: var(--bg-panel); padding: 15px 20px; border-radius: 8px; margin-bottom: 20px; display: flex; justify-content: space-between; align-items: center; flex-wrap: wrap; border-left: 5px solid var(--primary-color); border-top: 1px solid #1f2937; border-right: 1px solid #1f2937; border-bottom: 1px solid #1f2937;
 196 |         }
 197 |         .status-item { font-size: 14px; margin: 2px 0; color: #9ca3af; }
 198 |         .status-item span { font-weight: bold; color: var(--warning); }
 199 |         .sync-badge { padding: 3px 7px; border-radius: 4px; font-size: 11px; font-weight: bold; display: inline-block; }
 200 |         .sync-success { background-color: rgba(16, 185, 129, 0.15); color: #34d399; border: 1px solid var(--success); }
 201 |         .sync-loading { background-color: rgba(59, 130, 246, 0.15); color: #60a5fa; border: 1px solid #3b82f6; }
 202 |         #clock { font-family: 'Courier New', Courier, monospace; font-size: 48px; color: var(--success); font-weight: bold; text-shadow: 0 0 16px rgba(16, 185, 129, 0.35); letter-spacing: 2px; }
