 207 |         .vcc-pre-table td { padding: 12px 14px; border-bottom: 1px solid #1f2937; color: #e5e7eb; }
 208 |         .status-badge { padding: 2px 6px; border-radius: 4px; font-size: 11px; font-weight: bold; }
