 212 |         .btn-action { padding: 4px 8px; font-size: 11px; margin-right: 4px; border-radius: 4px; cursor: pointer; color: white; border: none;}
 213 |         .btn-action-edit { background-color: #d97706; }
 214 |         .btn-action-copy { background-color: #0891b2; }
 215 |         .btn-action-del { background-color: #dc2626; }
