2099 |         try {
2100 |             const opts = { timeZone: tz, hour12: false };
2101 |             const dateStr = now.toLocaleDateString('en-CA', opts);
2102 |             const timeStr = now.toLocaleTimeString('en-US', opts);
2103 |             const dp = dateStr.split('-');
2104 |             const tp = timeStr.split(':');
2105 |             return new Date(parseInt(dp[0]), parseInt(dp[1])-1, parseInt(dp[2]), parseInt(tp[0]), parseInt(tp[1]), parseInt(tp[2]), now.getMilliseconds());
2106 |         } catch(e) {
2107 |             return new Date(Date.now() + timeOffset);
2108 |         }
2109 |     }
