2776 |     function calculateGlobalTimelineMatrix(isHotReload) {
2777 |         const targetDateStr = document.getElementById('globalTargetDate').value;
2778 |         const activeList = getExpandedRundownForDate(targetDateStr);
2779 | 
2780 |         // Build progColorMap from active list
2781 |         const uniqueProgNames = [];
2782 |         const seenNames = {};
2783 |         activeList.forEach(function(p) {
2784 |             if (!seenNames[p.id]) { seenNames[p.id] = true; uniqueProgNames.push(p.name); }
2785 |         });
2786 |         uniqueProgNames.forEach(function(name, idx) {
2787 |             // 檢查是否有 colorLabel → 取最接近的 MATRIX_COLORS 索引
2788 |             let clrOverride = null;
2789 |             activeList.forEach(function(p) { if (p.name === name && p.colorLabel) clrOverride = p.colorLabel; });
2790 |             if (clrOverride) {
2791 |                 let bestDiff = Infinity, bestIdx = 0;
2792 |                 for (let ci = 0; ci < MATRIX_COLORS.length; ci++) {
2793 |                     const diff = Math.abs(parseInt(clrOverride.slice(1),16) - parseInt(MATRIX_COLORS[ci].slice(1),16));
2794 |                     if (diff < bestDiff) { bestDiff = diff; bestIdx = ci; }
2795 |                 }
2796 |                 progColorMap[name] = bestIdx;
2797 |             } else {
2798 |                 progColorMap[name] = idx % 8;
2799 |             }
2800 |         });
