2807 |             const df = timecodeToTotalFrames(prog.duration);
2808 |             if (sf < timelineRange.minFrames) timelineRange.minFrames = sf;
2809 |             if (sf + df > timelineRange.maxFrames) timelineRange.maxFrames = sf + df;
2810 |         });
2811 |         if (timelineRange.maxFrames - timelineRange.minFrames < 90000) {
2812 |             const pad = 45000; // ~30min padding
2813 |             timelineRange.minFrames = Math.max(0, timelineRange.minFrames - pad);
2814 |             timelineRange.maxFrames = timelineRange.minFrames + 90000;
2815 |         }
2816 | 
2817 |         const triggeredBackup = {};
2818 |         globalTriggers.forEach(function(t) { triggeredBackup[t.fullNodeName] = t.triggered; });
2819 |         globalTriggers = [];
