2821 |         activeList.forEach(function(prog) {
2822 |             const startFrames = timecodeToTotalFrames(prog.startTime);
2823 |             const durFrames = timecodeToTotalFrames(prog.duration);
2824 |             const endFrames = startFrames + durFrames;
2825 | 
2826 |             prog.startTotalFrames = startFrames;
2827 |             prog.endTotalFrames = endFrames;
2828 |             progDurations[prog.name] = { startFrames: startFrames, endFrames: endFrames, progName: prog.name };
2829 | 
2830 |             const targetPreset = cuePresets[prog.presetId] ? cuePresets[prog.presetId] : cuePresets["std_news"];
2831 | 
2832 |             targetPreset.nodes.forEach(function(node) {
