2845 |                 let spMatch = null;
2846 |                 if (node.soundId) {
2847 |                     for (let si = 0; si < soundPresets.length; si++) {
2848 |                         if (soundPresets[si].id === node.soundId) { spMatch = soundPresets[si]; break; }
2849 |                     }
