3257 |     function playBroadcastBeep(customFreq, presetObj) {
3258 |         if (customFreq === 0 || (presetObj && presetObj.id === "silent")) return;
3259 |         try {
3260 |             const actx = window.audioCtx || new (window.AudioContext || window.webkitAudioContext)();
3261 |             if (actx.state === 'suspended') actx.resume();
3262 |             window.audioCtx = actx;
3263 | 
3264 |             // 如果傳入 soundPreset 物件，使用完整設定（含重複次數、波形）
3265 |             if (presetObj) {
3266 |                 const repeats = presetObj.repeats || 1;
3267 |                 const gap = presetObj.gap || 0;
3268 |                 const dur = presetObj.dur || 0.3;
3269 |                 const freq = presetObj.freq || customFreq || 1000;
3270 |                 let type = presetObj.type || 'sine';
3271 |                 for (let r = 0; r < repeats; r++) {
3272 |                     (function(idx) {
3273 |                         const offset = (dur + gap) * idx;
3274 |                         setTimeout(function() {
3275 |                             const osc = actx.createOscillator();
3276 |                             const gain = actx.createGain();
3277 |                             osc.connect(gain); gain.connect(actx.destination);
3278 |                             osc.type = type;
3279 |                             osc.frequency.value = freq;
3280 |                             gain.gain.setValueAtTime(0.3, actx.currentTime);
3281 |                             osc.start(); osc.stop(actx.currentTime + dur);
3282 |                         }, offset * 1000);
3283 |                     })(r);
3284 |                 }
3285 |                 return;
3286 |             }
3287 | 
3288 |             // 向後相容：只傳頻率數字
3289 |             const freq = customFreq || parseFloat(document.getElementById('cfgBeepFreq').value) || 1500;
3290 |             const duration = parseFloat(document.getElementById('cfgBeepDur').value) || 0.5;
3291 |             const osc = actx.createOscillator(); const gain = actx.createGain();
3292 |             osc.connect(gain); gain.connect(actx.destination);
3293 |             osc.type = 'sine'; osc.frequency.value = freq; gain.gain.setValueAtTime(0.3, actx.currentTime);
3294 |             osc.start(); osc.stop(actx.currentTime + duration);
3295 |         } catch (e) {}
3296 |     }
